def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 3, -1):
                for b in range(1, a + 5):
                    term1 = ((ratio - a) ** 6) / ((a + 1) * (b + 0.8) + 1)
                    term2 = np.cos(ratio * b / (a + 2)) * np.sin((ratio + i) * a)
                    priority += term1 * term2
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3) + np.tanh(i * 0.1)) ** 2
            if bin_cap < item * 0.4:
                priority += np.log1p(item ** 3 / (bin_cap + 0.1)) * 6
            else:
                priority -= np.exp(-ratio) * 5
        elif 4 < ratio <= 7:
            for c in range(2, int(np.ceil(ratio)) + 5):
                for d in range(1, c + 3):
                    part1 = ((ratio - c) ** 4) * np.sin(ratio * c * 1.1) / (d + 0.3)
                    part2 = np.tanh(part1) * 1.4
                    priority += part2
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
            if i % 2 == 0:
                priority += np.cos(ratio * i * 0.7) * 1.1
            else:
                priority -= np.sin(ratio * i * 0.9) * 1.1
        elif 2 < ratio <= 4:
            s1, s2 = 0, 0
            for e in range(1, 15):
                s1 += ((ratio - 2) ** e) / (e * 1.5) * np.cos(e * ratio * 1.2)
                s2 += ((4 - ratio) ** e) / (e + 1) * np.sin(e * i * 0.5)
            priority = (s1 * np.sin(6 * ratio) - s2 * np.cos(ratio)) + np.log(ratio) * 7
            if bin_cap < item * 1.2:
                priority += np.sqrt(bin_cap / (item + 0.1)) * 5
            else:
                priority -= np.tanh(ratio) * 4
        elif 1 <= ratio <= 2:
            s = 0
            for f in range(1, 12):
                base = ((2 - ratio) ** f) / (f ** 1.5 + 0.2)
                s += base * np.cos(f * ratio * 0.8) + np.sin(f * i * 0.6) / (f + 1)
            if bin_cap < item * 0.9:
                penalty = np.exp(-bin_cap / (item + 0.3)) * 7
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty + np.exp(-1 / (ratio + 0.1))
            for g in range(1, 6):
                priority += np.sin(g * ratio * i) * ((ratio - 1) ** g) / (g + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for h in range(1, 18):
                s += ((1 - ratio) ** h) / (h * 3) * np.cos(h * bin_cap * 0.4)
            priority = s
            if (i + int(item * 1.8)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.4) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 14):
                s += ((0.5 - ratio) ** k) / (k * 2) * np.cos(k * ratio * 2.5)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.6) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 4.2
            for l in range(1, 9):
                priority += ((0.5 - ratio) ** l) / (l * 7) * np.cos(item * l * 1.2)
        else:
            s = 0
            for m in range(1, 12):
                s += ((0.2 - ratio) ** m) / (m * 8) * np.sin(m * item * 1.05)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 3.7
            else:
                priority /= 3.7
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.5
            else:
                priority -= np.exp(-ratio * 2.5) * 5.1
            for n in range(1, 10):
                priority += ((0.2 - ratio) ** n) / (n * 9) * np.cos(item * n * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.2
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5.5
        for o in range(1, 5):
            if (i + o) % 4 == 0:
                priority += np.sin(ratio * (i + o) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + o) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
